package com.games.controller;import com.games.dto.*;import com.games.service.AuthService;import jakarta.validation.Valid;import lombok.RequiredArgsConstructor;import org.springframework.http.HttpStatus;import org.springframework.http.ResponseEntity;import org.springframework.web.bind.annotation.*;import java.util.Map;@RestController@RequestMapping("/api/auth")@RequiredArgsConstructorpublic class AuthController {    private final AuthService authService;    /**     * POST /api/auth/register     * Returns user info on successful registration.     */    @PostMapping("/register")    public ResponseEntity<RegisterResponse> register(@Valid @RequestBody RegisterRequest request) {        RegisterResponse response = authService.register(request);        return ResponseEntity.status(HttpStatus.CREATED).body(response);    }    /**     * POST /api/auth/login     * Returns ONLY the JWT token as plain string (per spec).     */    @PostMapping("/login")    public ResponseEntity<?> login(@RequestBody LoginRequest request) {        String token = authService.login(request);        return ResponseEntity.status(HttpStatus.OK)                .body(                        Map.of(                                "token",token                        )                );    }}